def solve(nums: Array[Long], k: Long): Long = {
    val n = nums.length
    if (n == 0) return 0L
    val sorted = nums.sorted
    var maxLen = 1L
    for (i <- 0 until n) {
        val target = sorted(i) * k
        var low = i
        var high = n - 1
        var bestJ = i - 1
        while (low <= high) {
            val mid = (low + high) / 2
            if (sorted(mid) <= target) {
                bestJ = mid
                low = mid + 1
            } else {
                high = mid - 1
            }
        }
        if (bestJ >= i) {
            val currentLen = bestJ - i + 1
            if (currentLen > maxLen) {
                maxLen = currentLen
            }
        }
    }
    n - maxLen
}
